1333:     assert((unsigned)SVT.SimpleTy < std::size(TransformToType));
1334:     MVT NVT = TransformToType[SVT.SimpleTy];
1335:     LegalizeTypeAction LA = ValueTypeActions.getTypeAction(SVT);
1336: 
1337:     assert((LA == TypeLegal || LA == TypeSoftenFloat ||
1338:             LA == TypeSoftPromoteHalf ||
1339:             (NVT.isVector() ||
1340:              ValueTypeActions.getTypeAction(NVT) != TypePromoteInteger)) &&
1341:            "Promote may not follow Expand or Promote");
1342: 
1343:     if (LA == TypeSplitVector)
1344:       return LegalizeKind(LA, EVT(SVT).getHalfNumVectorElementsVT(Context));
1345:     if (LA == TypeScalarizeVector)
1346:       return LegalizeKind(LA, SVT.getVectorElementType());
1347:     return LegalizeKind(LA, NVT);
1348:   }
1349: 
1350:   // Handle Extended Scalar Types.
1351:   if (!VT.isVector()) {
1352:     assert(VT.isInteger() && "Float types must be simple");
1353:     unsigned BitSize = VT.getSizeInBits();
1354:     // First promote to a power-of-two size, then expand if necessary.
1355:     if (BitSize < 8 || !isPowerOf2_32(BitSize)) {
1356:       EVT NVT = VT.getRoundIntegerType(Context);
1357:       assert(NVT != VT && "Unable to round integer VT");
1358:       LegalizeKind NextStep = getTypeConversion(Context, NVT);
1359:       // Avoid multi-step promotion.
1360:       if (NextStep.first == TypePromoteInteger)
1361:         return NextStep;
1362:       // Return rounded integer type.
1363:       return LegalizeKind(TypePromoteInteger, NVT);
1364:     }
1365: 
1366:     return LegalizeKind(TypeExpandInteger,
1367:                         EVT::getIntegerVT(Context, VT.getSizeInBits() / 2));
1368:   }
1369: 
1370:   // Handle vector types.
1371:   ElementCount NumElts = VT.getVectorElementCount();
1372:   EVT EltVT = VT.getVectorElementType();
1373: 
1374:   // Vectors with only one element are always scalarized.
1375:   if (NumElts.isScalar())
1376:     return LegalizeKind(TypeScalarizeVector, EltVT);
1377: 
1378:   // Try to widen vector elements until the element type is a power of two and
1379:   // promote it to a legal type later on, for example:
1380:   // <3 x i8> -> <4 x i8> -> <4 x i32>
1381:   if (EltVT.isInteger()) {
1382:     // Vectors with a number of elements that is not a power of two are always
1383:     // widened, for example <3 x i8> -> <4 x i8>.
1384:     if (!VT.isPow2VectorType()) {
1385:       NumElts = NumElts.coefficientNextPowerOf2();
1386:       EVT NVT = EVT::getVectorVT(Context, EltVT, NumElts);
1387:       return LegalizeKind(TypeWidenVector, NVT);
1388:     }
1389: 
1390:     // Examine the element type.
1391:     LegalizeKind LK = getTypeConversion(Context, EltVT);
1392: 
1393:     // If type is to be expanded, split the vector.
1394:     //  <4 x i140> -> <2 x i140>
1395:     if (LK.first == TypeExpandInteger) {
1396:       if (NumElts.isScalable() && NumElts.getKnownMinValue() == 1)
1397:         return LegalizeKind(TypeScalarizeScalableVector, EltVT);
1398:       return LegalizeKind(TypeSplitVector,
1399:                           VT.getHalfNumVectorElementsVT(Context));
1400:     }
