1402:     // Promote the integer element types until a legal vector type is found
1403:     // or until the element integer type is too big. If a legal type was not
1404:     // found, fallback to the usual mechanism of widening/splitting the
1405:     // vector.
1406:     EVT OldEltVT = EltVT;
1407:     while (true) {
1408:       // Increase the bitwidth of the element to the next pow-of-two
1409:       // (which is greater than 8 bits).
1410:       EltVT = EVT::getIntegerVT(Context, 1 + EltVT.getSizeInBits())
1411:                   .getRoundIntegerType(Context);
1412: 
1413:       // Stop trying when getting a non-simple element type.
1414:       // Note that vector elements may be greater than legal vector element
1415:       // types. Example: X86 XMM registers hold 64bit element on 32bit
1416:       // systems.
1417:       if (!EltVT.isSimple())
1418:         break;
1419: 
1420:       // Build a new vector type and check if it is legal.
1421:       MVT NVT = MVT::getVectorVT(EltVT.getSimpleVT(), NumElts);
1422:       // Found a legal promoted vector type.
1423:       if (NVT != MVT() && ValueTypeActions.getTypeAction(NVT) == TypeLegal)
1424:         return LegalizeKind(TypePromoteInteger,
1425:                             EVT::getVectorVT(Context, EltVT, NumElts));
1426:     }
1427: 
1428:     // Reset the type to the unexpanded type if we did not find a legal vector
1429:     // type with a promoted vector element type.
1430:     EltVT = OldEltVT;
1431:   }
1432: 
1433:   // Try to widen the vector until a legal type is found.
1434:   // If there is no wider legal type, split the vector.
1435:   while (true) {
1436:     // Round up to the next power of 2.
1437:     NumElts = NumElts.coefficientNextPowerOf2();
1438: 
1439:     // If there is no simple vector type with this many elements then there
1440:     // cannot be a larger legal vector type.  Note that this assumes that
1441:     // there are no skipped intermediate vector types in the simple types.
1442:     if (!EltVT.isSimple())
1443:       break;
1444:     MVT LargerVector = MVT::getVectorVT(EltVT.getSimpleVT(), NumElts);
1445:     if (LargerVector == MVT())
1446:       break;
1447: 
1448:     // If this type is legal then widen the vector.
1449:     if (ValueTypeActions.getTypeAction(LargerVector) == TypeLegal)
1450:       return LegalizeKind(TypeWidenVector, LargerVector);
1451:   }
1452: 
1453:   // Widen odd vectors to next power of two.
1454:   if (!VT.isPow2VectorType()) {
